"""
Reusable Dash UI components for SRT simulator dashboards.

Provides factory functions for sliders, buttons, status displays,
sidebar layout, and graph grids.
"""

from dash import dcc, html, Input, Output, callback


def make_slider(pid, lo, hi, step, val, label):
    """Standard slider with tooltip."""
    return html.Div([
        html.Label(label, style={"fontSize": "11px", "color": "#555"}),
        dcc.Slider(
            id=f"slider-{pid}",
            min=lo, max=hi, step=step, value=val,
            marks=None,
            tooltip={"placement": "right", "always_visible": True},
        ),
    ], style={"marginBottom": "4px"})


def make_slider_group(title, slider_defs):
    """Section header + list of sliders.

    slider_defs: list of (pid, lo, hi, step, val, label) tuples.
    """
    children = [html.H4(title, style={"marginTop": "8px", "marginBottom": "4px"})]
    for args in slider_defs:
        children.append(make_slider(*args))
    return html.Div(children)


def make_dropdown(pid, options, default, label):
    """Labeled dropdown.

    options: list of (label_text, value) tuples.
    """
    return html.Div([
        html.Label(label, style={"fontSize": "12px", "fontWeight": "bold"}),
        dcc.Dropdown(
            id=f"dd-{pid}",
            options=[{"label": lbl, "value": val} for lbl, val in options],
            value=default,
            clearable=False,
            style={"fontSize": "12px", "marginBottom": "6px"},
        ),
    ])


def make_start_stop_buttons(include_reset=False):
    """Start/Stop (optionally Reset) buttons + status div + hidden stores.

    Returns a list of Dash components to append to a sidebar.
    """
    btn_style = lambda color: {
        "backgroundColor": color, "color": "white", "border": "none",
        "padding": "8px 20px", "fontSize": "14px", "fontWeight": "bold",
        "borderRadius": "4px", "cursor": "pointer", "marginRight": "6px",
    }

    buttons = [
        html.Button("Start", id="btn-start", n_clicks=0, style=btn_style("#28a745")),
        html.Button("Stop", id="btn-stop", n_clicks=0, style=btn_style("#dc3545")),
    ]
    if include_reset:
        buttons.append(
            html.Button("Reset", id="btn-reset", n_clicks=0, style=btn_style("#6c757d"))
        )

    components = [
        html.Hr(),
        html.Div([
            html.Div(buttons, style={
                "display": "flex", "justifyContent": "center", "marginBottom": "8px",
            }),
            html.Div(
                id="sim-status",
                children="Idle",
                style={
                    "textAlign": "center", "fontSize": "13px", "fontWeight": "bold",
                    "padding": "4px", "borderRadius": "4px", "backgroundColor": "#f0f0f0",
                },
            ),
        ], style={"marginTop": "4px"}),
        dcc.Store(id="store-start-clicks", data=0),
        dcc.Store(id="store-stop-clicks", data=0),
    ]
    return components


def status_from_stream(client, default_duration=30.0):
    """Compute status text and style from stream data.

    Returns (status_text, status_style) tuple.
    """
    running_val = client.get_latest("running")
    elapsed_val = client.get_latest("elapsed")
    duration_val = client.get_latest("duration")

    is_running = running_val is not None and running_val >= 0.5
    elapsed_s = elapsed_val if elapsed_val is not None else 0.0
    dur_s = duration_val if duration_val is not None else default_duration

    base = {
        "textAlign": "center", "fontSize": "13px", "fontWeight": "bold",
        "padding": "4px", "borderRadius": "4px",
    }

    if is_running:
        return (
            f"Running: {elapsed_s:.1f} / {dur_s:.0f} s",
            {**base, "backgroundColor": "#d4edda", "color": "#155724"},
        )
    elif elapsed_s > 0.5:
        return (
            f"Finished: {elapsed_s:.1f} s",
            {**base, "backgroundColor": "#fff3cd", "color": "#856404"},
        )
    else:
        return (
            "Idle",
            {**base, "backgroundColor": "#f0f0f0", "color": "#333"},
        )


def make_sidebar(children, width="280px"):
    """Wrap children in the standard scrollable sidebar div."""
    return html.Div(
        children,
        style={
            "width": width, "padding": "10px", "overflowY": "auto",
            "borderRight": "1px solid #ccc", "height": "100vh",
        },
    )


def make_2x2_grid(graph_ids):
    """Standard 2x2 graph grid.

    graph_ids: [top_left, bottom_left, top_right, bottom_right]
    """
    return html.Div([
        html.Div([
            dcc.Graph(id=graph_ids[0], style={"height": "45vh"}),
            dcc.Graph(id=graph_ids[1], style={"height": "45vh"}),
        ], style={"flex": "1"}),
        html.Div([
            dcc.Graph(id=graph_ids[2], style={"height": "45vh"}),
            dcc.Graph(id=graph_ids[3], style={"height": "45vh"}),
        ], style={"flex": "1"}),
    ], style={"display": "flex", "flex": "1"})


def make_app_layout(sidebar, graph_ids, interval_ms=200):
    """Full page layout: interval + sidebar + 2x2 grid."""
    return html.Div([
        dcc.Interval(id="interval", interval=interval_ms, n_intervals=0),
        html.Div([
            sidebar,
            make_2x2_grid(graph_ids),
        ], style={"display": "flex", "height": "100vh"}),
    ])


def register_start_stop_callbacks(app):
    """Register the standard btn-start/btn-stop -> store callbacks."""

    @app.callback(
        Output("store-start-clicks", "data"),
        Input("btn-start", "n_clicks"),
        prevent_initial_call=True,
    )
    def on_start_click(n):
        return n

    @app.callback(
        Output("store-stop-clicks", "data"),
        Input("btn-stop", "n_clicks"),
        prevent_initial_call=True,
    )
    def on_stop_click(n):
        return n
